svg.script:
//
(function () {
  var DIM  = '0.15';
  var FULL = '1';

  function activate(n) {
    for (var i = 1; i <= 4; i++) {
      var on = (i === n);
      var icon  = document.getElementById('icon-'  + i);
      var conn  = document.getElementById('conn-'  + i);
      var arrow = document.getElementById('arrow-' + i);
      if (icon)  icon.style.opacity  = on ? FULL : DIM;
      if (conn)  conn.style.opacity  = on ? FULL : DIM;
      if (arrow) arrow.style.opacity = on ? FULL : '0';
    }
  }

  window.addEventListener('message', function (e) {
    if (e.data && e.data.activeSection) activate(e.data.activeSection);
  });

  /* default: section 1 active */
  window.addEventListener('load', function () { activate(1); });
})();
//
